+/// Numeric trait for generic math.
+pub trait Numeric: Copy + std::ops::Add<Output = Self> + std::ops::Mul<Output = Self> {
+    fn zero() -> Self;
+    fn one() -> Self;
+}
+
+impl Numeric for i32 {
+    fn zero() -> Self { 0 }
+    fn one() -> Self { 1 }
+}
