+
+/// Sieve of Eratosthenes for finding primes.
+pub fn sieve_of_eratosthenes(limit: usize) -> Vec<usize> {
+    if limit < 2 {
+        return vec![];
+    }
+
+    let mut is_prime = vec![true; limit + 1];
+    is_prime[0] = false;
+    is_prime[1] = false;
+
+    let sqrt_limit = (limit as f64).sqrt() as usize + 1;
+    for i in 2..sqrt_limit {
+        if is_prime[i] {
+            for j in (i * i..=limit).step_by(i) {
+                is_prime[j] = false;
+            }
+        }
+    }
+
+    is_prime
+        .into_iter()
+        .enumerate()
+        .filter(|(_, is_p)| *is_p)
+        .map(|(i, _)| i)
+        .collect()
+}
+
+/// Create a matrix filled with a value.
+pub fn create_matrix(rows: usize, cols: usize, value: f64) -> Vec<Vec<f64>> {
+    vec![vec![value; cols]; rows]
+}
+
+/// Matrix multiplication.
+pub fn matrix_multiply(a: &[Vec<f64>], b: &[Vec<f64>]) -> Vec<Vec<f64>> {
+    let rows_a = a.len();
+    let cols_a = if rows_a > 0 { a[0].len() } else { 0 };
+    let cols_b = if !b.is_empty() { b[0].len() } else { 0 };
+
+    let mut result = vec![vec![0.0; cols_b]; rows_a];
+
+    for i in 0..rows_a {
+        for j in 0..cols_b {
+            for k in 0..cols_a {
+                result[i][j] += a[i][k] * b[k][j];
+            }
+        }
+    }
+
+    result
+}
+
+/// Fibonacci using iteration.
+pub fn fibonacci_iterative(n: u64) -> u64 {
+    if n <= 1 {
+        return n;
+    }
+
+    let mut prev = 0u64;
+    let mut curr = 1u64;
+
+    for _ in 2..=n {
+        let next = prev.wrapping_add(curr);
+        prev = curr;
+        curr = next;
+    }
+
+    curr
+}
+
+/// Factorial using iteration.
+pub fn factorial(n: u64) -> u64 {
+    (1..=n).product()
+}
+
+/// GCD using Euclidean algorithm.
+pub fn gcd(mut a: u64, mut b: u64) -> u64 {
+    while b != 0 {
+        let temp = b;
+        b = a % b;
+        a = temp;
+    }
+    a
+}
+
+/// LCM using GCD.
+pub fn lcm(a: u64, b: u64) -> u64 {
+    if a == 0 || b == 0 {
+        return 0;
+    }
+    (a / gcd(a, b)) * b
+}
+
+/// Merge sort implementation.
+pub fn merge_sort<T: Ord + Clone>(arr: &mut [T]) {
+    let len = arr.len();
+    if len <= 1 {
+        return;
+    }
+
+    let mid = len / 2;
+    merge_sort(&mut arr[..mid]);
+    merge_sort(&mut arr[mid..]);
+
+    let left = arr[..mid].to_vec();
+    let right = arr[mid..].to_vec();
+
+    let mut i = 0;
+    let mut j = 0;
+    let mut k = 0;
+
+    while i < left.len() && j < right.len() {
+        if left[i] <= right[j] {
+            arr[k] = left[i].clone();
+            i += 1;
+        } else {
+            arr[k] = right[j].clone();
+            j += 1;
+        }
+        k += 1;
+    }
+
+    while i < left.len() {
+        arr[k] = left[i].clone();
+        i += 1;
+        k += 1;
+    }
+
+    while j < right.len() {
+        arr[k] = right[j].clone();
+        j += 1;
+        k += 1;
+    }
+}
+
+/// Quick sort implementation.
+pub fn quick_sort<T: Ord>(arr: &mut [T]) {
+    if arr.len() <= 1 {
+        return;
+    }
+
+    let pivot_idx = partition(arr);
+
+    if pivot_idx > 0 {
+        quick_sort(&mut arr[..pivot_idx]);
+    }
+    quick_sort(&mut arr[pivot_idx + 1..]);
+}
+
+fn partition<T: Ord>(arr: &mut [T]) -> usize {
+    let len = arr.len();
+    let pivot_idx = len / 2;
+    arr.swap(pivot_idx, len - 1);
+
+    let mut i = 0;
+    for j in 0..len - 1 {
+        if arr[j] <= arr[len - 1] {
+            arr.swap(i, j);
+            i += 1;
+        }
+    }
+
+    arr.swap(i, len - 1);
+    i
+}
+
+/// Binary search.
+pub fn binary_search<T: Ord>(arr: &[T], target: &T) -> Option<usize> {
+    let mut left = 0;
+    let mut right = arr.len();
+
+    while left < right {
+        let mid = left + (right - left) / 2;
+        match arr[mid].cmp(target) {
+            std::cmp::Ordering::Equal => return Some(mid),
+            std::cmp::Ordering::Less => left = mid + 1,
+            std::cmp::Ordering::Greater => right = mid,
+        }
+    }
+
+    None
+}
+
+/// N-Queens problem solver (count solutions).
+pub fn n_queens(n: usize) -> usize {
+    let mut count = 0;
+    let mut board = vec![0usize; n];
+    solve_n_queens(&mut board, 0, n, &mut count);
+    count
+}
+
+fn solve_n_queens(board: &mut [usize], row: usize, n: usize, count: &mut usize) {
+    if row == n {
+        *count += 1;
+        return;
+    }
+
+    for col in 0..n {
+        if is_safe(board, row, col) {
+            board[row] = col;
+            solve_n_queens(board, row + 1, n, count);
+        }
+    }
+}
+
+fn is_safe(board: &[usize], row: usize, col: usize) -> bool {
+    for i in 0..row {
+        let placed_col = board[i];
+        if placed_col == col {
+            return false;
+        }
+        let row_diff = row - i;
+        let col_diff = if col > placed_col {
+            col - placed_col
+        } else {
+            placed_col - col
+        };
+        if row_diff == col_diff {
+            return false;
+        }
+    }
+    true
+}
